    /* case 1  lb=3=unbound  rb=1=closed   lu   !ru  lv=rv  greater     */  TEST_EQUAL(B::compare(uu1, cl1), 1);
    /* case 1  lb=3=unbound  rb=1=closed   lu   !ru  lv>rv  greater     */  TEST_EQUAL(B::compare(uu2, cl1), 1);
    /* case 1  lb=3=unbound  rb=1=closed   lu   ru   lv<rv  greater     */  TEST_EQUAL(B::compare(uu1, cu2), 1);
