    /* case 7  lb=2=open     rb=2=open     !lu  !ru  lv<rv  lv<=>rv     */  TEST_EQUAL(B::compare(ol1, ol2), -1);
    /* case 7  lb=2=open     rb=2=open     !lu  !ru  lv=rv  lv<=>rv     */  TEST_EQUAL(B::compare(ol1, ol1), 0);
